// This configuration is automatically generated and populated by Firebase Studio
// Do not edit this file manually.

export const DUMMY_API_KEY = "dummy-api-key-for-local-development";

export function getFirebaseConfig() {
  const firebaseConfig = {
    apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY,
    authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN,
    projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID,
    storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET,
    messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID,
    appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID,
  };

  // If the config is not set, use dummy values to prevent app crash during development.
  // This allows UI development without a real Firebase backend.
  if (!firebaseConfig.apiKey) {
    console.warn("Firebase config is not set. Using dummy values for development. Authentication and database features will be disabled.");
    return {
      apiKey: DUMMY_API_KEY,
      authDomain: "dummy-project.firebaseapp.com",
      projectId: "dummy-project",
      storageBucket: "dummy-project.appspot.com",
      messagingSenderId: "1234567890",
      appId: "1:1234567890:web:dummy",
    };
  }

  return firebaseConfig;
}
